## 2b  Hex-binned density — sampling intensity

The aggregate view bins sites into flat-top hexagons in plain
longitude–latitude space, and colour-codes each hex by how many
SISAL sites fall inside it. A sequential ramp (yellow → red) makes
the densely-sampled regions (Europe, East Asia, Australasia) pop
out immediately.

::: {.callout-note title="Projection choice"}
The hexagons are built directly in the `(lon, lat)` grid with no
latitude correction, then handed to Leaflet which projects them to
Web Mercator like everything else on the map. That means hexes far
from the equator look *taller* than ones near it — the same
latitude-dependent distortion that affects every Mercator map.
Proper equal-area binning (Mollweide or similar) would need
`pyproj`, an extra ~10 MB Pyodide download; for a teaching overview
at global scale the honest Mercator view is a reasonable trade-off.
:::


::: {.cell autorun='false'}
```{pyodide}
#| label: map-hexbin
#| autorun: false
import math, json, uuid
from collections import Counter

assert 'df' in dir() and not df.empty, "⚠ Run the data-loading cell first."

# ── Hexagons in plain (lon, lat) space ───────────────────────────────────
# No cosine correction: we let Leaflet's Mercator projection do the
# visual work. Hexes therefore cover a fixed lat/lon extent, not a fixed
# ground-area. Good enough for a global-scale sampling-density view.
HEX_SIZE_DEG = 6.0    # degrees; ~670 km at equator, narrower poleward

def point_to_hex(lon, lat, size):
    x, y = lon, lat
    q =  (2/3) * x / size
    r = -(1/3) * x / size + (math.sqrt(3)/3) * y / size
    cx, cz = q, r; cy = -cx - cz
    rx, ry, rz = round(cx), round(cy), round(cz)
    dx, dy, dz = abs(rx - cx), abs(ry - cy), abs(rz - cz)
    if dx > dy and dx > dz:   rx = -ry - rz
    elif dy > dz:             ry = -rx - rz
    else:                     rz = -rx - ry
    return int(rx), int(rz)

def hex_polygon(q, r, size):
    """Six (lat, lon) corners of a flat-top hex at axial coords (q, r)."""
    cx = size * 1.5 * q
    cy = size * math.sqrt(3) * (r + q/2)
    return [(cy + size * math.sin(math.radians(60*i)),
             cx + size * math.cos(math.radians(60*i))) for i in range(6)]

counts = Counter(point_to_hex(row["lon"], row["lat"], HEX_SIZE_DEG)
                 for _, row in df.iterrows())
max_n  = max(counts.values()) if counts else 1
ramp   = ["#ffffb2", "#fecc5c", "#fd8d3c", "#f03b20", "#bd0026"]

def ramp_idx(n):
    return min(len(ramp) - 1, int((n - 1) / max(max_n - 1, 1) * (len(ramp) - 1)))

features = [{
    "polygon": hex_polygon(q, r, HEX_SIZE_DEG),
    "count":   n,
    "color":   ramp[ramp_idx(n)],
} for (q, r), n in counts.items()]

# ── Legend bins: integer count ranges per ramp step ──────────────────────
step = max((max_n - 1) / len(ramp), 1)
legend = []
for i, col in enumerate(ramp):
    lo = int(1 + i * step)
    hi = int(1 + (i + 1) * step) - 1 if i < len(ramp) - 1 else max_n
    label = f"{lo}" if lo == hi else f"{lo}–{hi}"
    legend.append({"color": col, "label": label})

payload = json.dumps({"features": features, "legend": legend, "n_sites": len(df)})
map_id   = f"sisal-hexbin-{uuid.uuid4().hex[:8]}"
data_var = f"__sisalHexData_{map_id.replace('-', '_')}"

map_html = f"""
<div id="{map_id}" style="height:560px;width:100%;border:1px solid #ddd;border-radius:4px"></div>
<link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css" />
<link rel="stylesheet" href="https://unpkg.com/leaflet.fullscreen@3.0.2/Control.FullScreen.css" />
<script>window["{data_var}"] = {payload};</script>
<script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"></script>
<script>
(function() {{
    const mapId = "{map_id}";
    const data  = window["{data_var}"];

    function loadFullscreen(cb) {{
        if (typeof L !== 'undefined' && L.control && L.control.fullscreen) return cb();
        if (typeof L === 'undefined') return setTimeout(() => loadFullscreen(cb), 50);
        const s = document.createElement('script');
        s.src = 'https://unpkg.com/leaflet.fullscreen@3.0.2/Control.FullScreen.js';
        s.onload = cb;
        document.head.appendChild(s);
    }}

    let attempts = 0;
    function init() {{
        const el = document.getElementById(mapId);
        if (!el || typeof L === 'undefined') return setTimeout(init, 50);
        if (el._leaflet_id) return;
        const hasFullscreen = !!(L.control && L.control.fullscreen);
        if (!hasFullscreen && attempts < 40) {{ attempts++; return setTimeout(init, 50); }}

        const osm = L.tileLayer('https://{{s}}.tile.openstreetmap.org/{{z}}/{{x}}/{{y}}.png', {{
            maxZoom: 19,
            attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
        }});
        const esriTerrain = L.tileLayer(
            'https://server.arcgisonline.com/ArcGIS/rest/services/World_Terrain_Base/MapServer/tile/{{z}}/{{y}}/{{x}}', {{
            maxZoom: 13,
            attribution: 'Tiles &copy; Esri &mdash; Source: USGS, Esri, TANA, DeLorme, and NPS'
        }});

        const hexGroup = L.layerGroup();
        for (const f of data.features) {{
            L.polygon(f.polygon, {{
                color: "#444", weight: 0.6,
                fillColor: f.color, fillOpacity: 0.7,
            }}).bindTooltip(
                "<b>" + f.count + "</b> site" + (f.count !== 1 ? "s" : ""),
                {{ sticky: true }}
            ).addTo(hexGroup);
        }}

        const mapOpts = {{ center: [20, 10], zoom: 2, worldCopyJump: true,
                         layers: [osm, hexGroup] }};
        if (hasFullscreen) {{
            mapOpts.fullscreenControl = true;
            mapOpts.fullscreenControlOptions = {{ position: 'topleft' }};
        }}
        const map = L.map(mapId, mapOpts);

        L.control.layers({{
            "OpenStreetMap":      osm,
            "Esri World Terrain": esriTerrain,
        }}, {{ "Hex-binned density": hexGroup }}, {{ collapsed: true }}).addTo(map);

        // ── Inline legend (bottom-right) ─────────────────────────────────
        const legend = L.control({{ position: 'bottomright' }});
        legend.onAdd = function() {{
            const div = L.DomUtil.create('div', 'info legend');
            div.style.cssText = 'background:rgba(255,255,255,0.92);padding:8px 10px;'
                + 'border-radius:4px;box-shadow:0 1px 4px rgba(0,0,0,0.2);'
                + 'font-size:12px;line-height:1.5;font-family:sans-serif';
            let html = '<div style="font-weight:bold;margin-bottom:4px">Sites per hex</div>';
            for (const b of data.legend) {{
                html += '<div><span style="display:inline-block;width:14px;height:14px;'
                     + 'background:' + b.color + ';border:1px solid #444;'
                     + 'margin-right:6px;vertical-align:middle"></span>' + b.label + '</div>';
            }}
            html += '<div style="margin-top:4px;color:#666;font-size:11px">n = '
                 + data.n_sites + ' SISAL sites</div>';
            div.innerHTML = html;
            return div;
        }};
        legend.addTo(map);

        setTimeout(() => map.invalidateSize(), 200);
    }}
    loadFullscreen(init);
}})();
</script>
"""

class _Html:
    def __init__(self, s): self._s = s
    def _repr_html_(self): return self._s
_Html(map_html)
```
